/**
 * Подтема PlasmaSdServiceTheme.OnLight
 */
@Composable
public fun PlasmaSdServiceTheme.OnLight(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable () -> Unit,
) {
    val currentColors = LocalPlasmaSdServiceColors.current
    val overrideColors = currentColors.copyAttrs(OnLightColorsOverride)
    val currentGradients = LocalPlasmaSdServiceGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnLightGradientsOverride)
    PlasmaSdServiceTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
